  1	import React, { FC, useMemo, useState } from 'react';
  2	
  3	import DataVolumeModel from '@kubevirt-ui/kubevirt-api/console/models/DataVolumeModel';
  4	import { V1VirtualMachine, V1Volume } from '@kubevirt-ui/kubevirt-api/kubevirt';
  5	import ConfirmActionMessage from '@kubevirt-utils/components/ConfirmActionMessage/ConfirmActionMessage';
  6	import {
  7	  getRemoveHotplugPromise,
  8	  produceVMDisks,
  9	} from '@kubevirt-utils/components/DiskModal/utils/helpers';
 10	import Loading from '@kubevirt-utils/components/Loading/Loading';
 11	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 12	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 13	import { buildOwnerReference, compareOwnerReferences } from '@kubevirt-utils/resources/shared';
 14	import { getDataVolumeTemplates, getDisks, getVolumes } from '@kubevirt-utils/resources/vm';
 15	import { k8sDelete, K8sResourceCommon, k8sUpdate } from '@openshift-console/dynamic-plugin-sdk';
 16	import { ButtonVariant, Checkbox, Stack, StackItem } from '@patternfly/react-core';
 17	
 18	import { updateDisks } from '../../../details/utils/utils';
 19	
 20	import useVolumeOwnedResource from './hooks/useVolumeOwnedResource';
 21	
 22	type DeleteDiskModalProps = {
 23	  isHotPluginVolume: boolean;
 24	  isOpen: boolean;
 25	  onClose: () => void;
 26	  vm: V1VirtualMachine;
 27	  volume: V1Volume;
 28	};
 29	
 30	const DeleteDiskModal: FC<DeleteDiskModalProps> = ({
 31	  isHotPluginVolume,
 32	  isOpen,
 33	  onClose,
 34	  vm,
 35	  volume,
 36	}) => {
 37	  const { t } = useKubevirtTranslation();
 38	  const [deleteOwnedResource, setDeleteOwnedResource] = useState(false);
 39	
 40	  const diskName = volume?.name;
 41	
 42	  const {
 43	    error: loadingError,
 44	    loaded,
 45	    volumeResource,
 46	    volumeResourceModel,
 47	    volumeResourceName,
 48	  } = useVolumeOwnedResource(vm, volume);
 49	
 50	  const updatedVirtualMachine = useMemo(() => {
 51	    const updatedDisks = (getDisks(vm) || [])?.filter(({ name }) => name !== diskName);
 52	    const updatedVolumes = (getVolumes(vm) || [])?.filter(({ name }) => name !== diskName);
 53	    const updatedDataVolumeTemplates = (getDataVolumeTemplates(vm) || [])?.filter(
 54	      (dvt) => dvt?.metadata?.name !== volumeResourceName,
 55	    );
 56	
 57	    const updatedVM = produceVMDisks(vm, (vmDraft: V1VirtualMachine) => {
 58	      vmDraft.spec.template.spec.domain.devices.disks = updatedDisks;
 59	      vmDraft.spec.template.spec.volumes = updatedVolumes;
 60	      vmDraft.spec.dataVolumeTemplates = updatedDataVolumeTemplates;
 61	    });
 62	    return updatedVM;
 63	  }, [vm, diskName, volumeResourceName]);
 64	
 65	  const onSubmit = (updatedVM: V1VirtualMachine) => {
 66	    const deletePromise = isHotPluginVolume
 67	      ? getRemoveHotplugPromise(vm, diskName)
 68	      : updateDisks(updatedVM);
 69	
 70	    return deletePromise.then(() => {
 71	      if (volumeResource) {
 72	        if (deleteOwnedResource) {
 73	          // we need to delete the owned resource
 74	          return k8sDelete({
 75	            json: undefined,
 76	            model: volumeResourceModel,
 77	            requestInit: undefined,
 78	            resource: volumeResource,
 79	          });
 80	        }
 81	        // we don't need to delete the owned resource
 82	        // so we remove the resource's ownerReference from the owned resource
 83	        const vmOwnerRef = buildOwnerReference(updatedVM);
 84	        const updatedVolumeOwnerReferences = volumeResource?.metadata?.ownerReferences?.filter(
 85	          (ref) => {
 86	            return !compareOwnerReferences(ref, vmOwnerRef);
 87	          },
 88	        );
 89	        const updatedResourceVolume = { ...volumeResource };
 90	        updatedResourceVolume.metadata.ownerReferences = updatedVolumeOwnerReferences;
 91	        return k8sUpdate({
 92	          data: updatedResourceVolume,
 93	          model: volumeResourceModel,
 94	          name: updatedResourceVolume?.metadata?.name,
 95	          ns: updatedResourceVolume?.metadata?.namespace,
 96	        });
 97	      }
 98	    });
 99	  };
100	
101	  return (
102	    <TabModal<K8sResourceCommon>
103	      headerText={t('Detach disk?')}
104	      isOpen={isOpen}
105	      modalError={loadingError}
106	      obj={updatedVirtualMachine}
107	      onClose={onClose}
108	      onSubmit={onSubmit}
109	      submitBtnText={t('Detach')}
110	      submitBtnVariant={ButtonVariant.danger}
111	    >
112	      <Stack hasGutter>
113	        <StackItem>
114	          <ConfirmActionMessage
115	            obj={{
116	              metadata: { name: diskName },
117	            }}
118	            action="detach"
119	          />
120	        </StackItem>
121	        {loaded && (
122	          <StackItem>
123	            {volumeResource && (
124	              <Checkbox
125	                label={t('Delete {{volumeResourceName}} {{modelLabel}}', {
126	                  modelLabel:
127	                    volumeResourceModel === DataVolumeModel
128	                      ? `${volumeResourceModel.label} and PVC`
129	                      : volumeResourceModel.label,
130	                  volumeResourceName,
131	                })}
132	                id="delete-owned-resource"
133	                isChecked={deleteOwnedResource}
134	                onChange={(_event, val) => setDeleteOwnedResource(val)}
135	              />
136	            )}
137	          </StackItem>
138	        )}
139	
140	        {!loaded && !loadingError && <Loading />}
141	      </Stack>
142	    </TabModal>
143	  );
144	};
145	
146	export default DeleteDiskModal;

